import{_ as i,c as e,o as l,ah as t}from"./chunks/framework.Cnj7lwEt.js";const c=JSON.parse('{"title":"AutoGen","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI框架/AutoGen-AI框架.md","filePath":"github汇总/AI框架/AutoGen-AI框架.md"}'),o={name:"github汇总/AI框架/AutoGen-AI框架.md"};function n(h,a,r,s,d,p){return l(),e("div",null,a[0]||(a[0]=[t(`<h1 id="autogen" tabindex="-1">AutoGen <a class="header-anchor" href="#autogen" aria-label="Permalink to “AutoGen”">​</a></h1><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>Microsoft</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>AI框架</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>开发多代理AI应用门槛高，需要处理复杂的交互逻辑，缺乏统一的框架和工具链</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><ul><li>用于创建多代理AI应用的框架</li><li>支持代理自主行动或与人类协作</li><li>提供分层可扩展设计</li><li>支持.NET和Python跨语言开发</li><li>包含无代码GUI工具AutoGen Studio</li></ul><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>由微软开发维护，生态系统完善</li><li>提供核心框架、开发者工具和应用方案</li><li>支持在不同抽象层级上使用，从高级API到底层组件</li><li>包含AgentChat API用于快速原型开发</li><li>包含Extensions API扩展能力</li><li>提供AutoGen Studio无代码GUI工具</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/microsoft/autogen" target="_blank" rel="noreferrer">https://github.com/microsoft/autogen</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>适用于想要开发多代理AI应用的开发者，支持Python 3.10或更高版本</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li>系统要求：支持Windows、macOS、Linux</li><li>Python版本：Python 3.10或更高版本 <ul><li>检查命令：<code>python --version</code></li><li>通过标准：版本号≥3.10</li></ul></li><li>OpenAI API密钥（如使用OpenAI模型）</li><li>网络连接（用于安装依赖和访问模型API）</li></ol><h3 id="主路径-安装与启动" tabindex="-1">主路径：安装与启动 <a class="header-anchor" href="#主路径-安装与启动" aria-label="Permalink to “主路径：安装与启动”">​</a></h3><h4 id="步骤1-安装autogen和openai客户端" tabindex="-1">步骤1：安装AutoGen和OpenAI客户端 <a class="header-anchor" href="#步骤1-安装autogen和openai客户端" aria-label="Permalink to “步骤1：安装AutoGen和OpenAI客户端”">​</a></h4><ul><li>步骤目标：安装AutoGen框架和必要的依赖</li><li>执行位置：终端/命令行</li><li>完整命令：<code>pip install -U &quot;autogen-agentchat&quot; &quot;autogen-ext[openai]&quot;</code></li><li>成功标志：命令执行完成，无错误提示</li><li>失败处理：检查Python版本是否符合要求，网络连接是否正常，使用<code>pip install --upgrade pip</code>更新pip后重试</li></ul><h4 id="步骤2-可选-安装autogen-studio-无代码gui" tabindex="-1">步骤2：（可选）安装AutoGen Studio（无代码GUI） <a class="header-anchor" href="#步骤2-可选-安装autogen-studio-无代码gui" aria-label="Permalink to “步骤2：（可选）安装AutoGen Studio（无代码GUI）”">​</a></h4><ul><li>步骤目标：安装无代码GUI工具</li><li>执行位置：终端/命令行</li><li>完整命令：<code>pip install -U &quot;autogenstudio&quot;</code></li><li>成功标志：命令执行完成，无错误提示</li><li>失败处理：检查Python版本是否符合要求，网络连接是否正常</li></ul><h4 id="步骤3-配置openai-api密钥" tabindex="-1">步骤3：配置OpenAI API密钥 <a class="header-anchor" href="#步骤3-配置openai-api密钥" aria-label="Permalink to “步骤3：配置OpenAI API密钥”">​</a></h4><ul><li>步骤目标：配置OpenAI API密钥以便使用OpenAI模型</li><li>执行位置：终端/命令行</li><li>完整命令（macOS/Linux）：<code>export OPENAI_API_KEY=&quot;sk-你的密钥&quot;</code></li><li>完整命令（Windows PowerShell）：<code>$env:OPENAI_API_KEY=&quot;sk-你的密钥&quot;</code></li><li>成功标志：环境变量设置成功</li><li>失败处理：确保替换为真实的API密钥，检查密钥格式是否正确</li></ul><h4 id="步骤4-可选-启动autogen-studio" tabindex="-1">步骤4：（可选）启动AutoGen Studio <a class="header-anchor" href="#步骤4-可选-启动autogen-studio" aria-label="Permalink to “步骤4：（可选）启动AutoGen Studio”">​</a></h4><ul><li>步骤目标：启动无代码GUI界面</li><li>执行位置：终端/命令行</li><li>完整命令：<code>autogenstudio ui --port 8080 --appdir ./my-app</code></li><li>成功标志：服务启动，可在浏览器访问<a href="http://localhost:8080" target="_blank" rel="noreferrer">http://localhost:8080</a></li><li>失败处理：检查端口8080是否被占用，可修改为其他端口</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ol><li>访问地址：<a href="http://localhost:8080" target="_blank" rel="noreferrer">http://localhost:8080</a>（如启动了AutoGen Studio）</li><li>检查命令：运行简单的Python脚本测试导入<div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> autogen_agentchat.agents </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> AssistantAgent</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">print</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;导入成功&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></li><li>预期返回：无错误，打印&quot;导入成功&quot;</li></ol><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li>现象：Python版本不兼容 <ul><li>可能原因：Python版本低于3.10</li><li>解决步骤：升级Python到3.10或更高版本</li></ul></li><li>现象：pip安装失败 <ul><li>可能原因：网络问题或pip版本过旧</li><li>解决步骤：更新pip（<code>pip install --upgrade pip</code>），检查网络连接，或使用国内镜像源</li></ul></li><li>现象：API密钥无效 <ul><li>可能原因：密钥错误或格式不正确</li><li>解决步骤：确认API密钥正确，检查环境变量设置是否成功</li></ul></li></ol><h3 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h3><p>README/仓库信息中未提供完整备选方案</p><h3 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h3><p>README中未提供Docker部署方案，也未详细说明所有可用的扩展功能，如需深入了解可访问官方文档：<a href="https://github.com/microsoft/autogen" target="_blank" rel="noreferrer">https://github.com/microsoft/autogen</a> <a href="/网络环境.html">海外网络环境配置 →</a></p>`,37)]))}const k=i(o,[["render",n]]);export{c as __pageData,k as default};
